+  prompt: string
+  onPromptChange: (v: string) => void
+  onGenerate: () => void
+  loading: boolean
+  error: string | null
+}) {
+  return (
+    <div className="space-y-2">
+      <label className="flex items-center gap-1 text-[10px] text-gray-500">
