+      >
+        {loading ? <Loader2 className="w-3 h-3 animate-spin" /> : <Sparkles className="w-3 h-3" />}
+        {loading ? 'Generating...' : 'Generate Query'}
+      </button>
+      {error && (
+        <p className="text-[10px] text-red-400">{error}</p>
+      )}
+    </div>
+  )
+}
